solution: ```class TweetCounts {
    unordered_map<string, vector<int>> tweets;
public:
    TweetCounts() {}

    void recordTweet(string tweetName, int time) {
        tweets[tweetName].push_back(time);
    }

    vector<int> getTweetCountsPerFrequency(string freq, string tweetName, int startTime, int endTime) {
        if (tweets.find(tweetName) == tweets.end()) return {};
        int chunk;
        if (freq == "minute") chunk = 60;
        else if (freq == "hour") chunk = 3600;
        else chunk = 86400;

        int n = (endTime - startTime) / chunk + 1;
        vector<int> res(n, 0);

        for (int t : tweets[tweetName]) {
            if (t < startTime || t > endTime) continue;
            int idx = (t - startTime) / chunk;
            res[idx]++;
        }
        return res;
    }
};
```
efficiency: HIGH
time complexity: O(N) per query, where N is the number of tweets for the given tweetName
space complexity: O(T) where T is the total number of tweets recorded
energy implications: LOW
explanation: Store tweet times in a hash map keyed by tweetName. For queries, compute chunk size from freq, then count tweets in each chunk by direct index calculation. Simple and cache-friendly; no sorting or binary search needed due to small query range constraint.

